parameters.jsCode:
const raw = $json.content.parts[0].text;

const cleaned = raw
  .replace(/```json/g, "")
  .replace(/```/g, "")
  .trim();

const invoice = JSON.parse(cleaned);

return {
  json: invoice
};

const invoice = $('Code in JavaScript').first().json;

// Get the PO from the connected input
const poRecord = $input.first().json.fields;

// Get the invoice Airtable record
const invoiceRecord = $('Search records').first().json;

const vendorMatch =
  invoice.vendor_name === poRecord["Vendor Name"];

const amountMatch =
  invoice.gross_amount === poRecord["Gross Amount"];

const poMatch =
  invoice.purchase_order_number === poRecord["PO Number"];

const approved =
  poRecord["Approval Status"] === "Approved";

return {
  json: {
    invoice_id: invoiceRecord.id,
    vendor_match: vendorMatch,
    amount_match: amountMatch,
    po_match: poMatch,
    approved: approved,
    validation_passed:
      vendorMatch &&
      amountMatch &&
      poMatch &&
      approved
  }
};

