parameters.jsCode:
const response = $input.first().json;

let text = response.content.parts[0].text;

// Extract JSON between first { and last }
const start = text.indexOf("{");
const end = text.lastIndexOf("}");

if (start === -1 || end === -1) {
  throw new Error("No JSON found");
}

text = text.substring(start, end + 1);

return [
  {
    json: JSON.parse(text)
  }
];

const response = $input.first().json;

// Get the Gemini response
let text = response.content.parts[0].text;

// Remove markdown code fences if present
text = text
  .replace(/^```json\s*/i, "")
  .replace(/^```\s*/i, "")
  .replace(/\s*```$/, "")
  .trim();

// Parse JSON
return [
  {
    json: JSON.parse(text)
  }
];

// AI output
const item = $input.first().json;

// Gmail message
const gmail = $('Get a message2').first().json;

// ----------------------------
// Gmail fields
// ----------------------------
item.customer_name =
  gmail.from?.value?.[0]?.name ||
  item.customer_name ||
  "Unknown";

item.sender_email =
  gmail.from?.value?.[0]?.address ||
  item.sender_email ||
  "";

item.subject =
  gmail.subject ||
  item.subject ||
  "";

item.email_body =
  gmail.text ||
  gmail.html ||
  item.email_body ||
  "";

// ----------------------------
// Defaults
// ----------------------------
item.company = item.company || "";
item.issue_summary = item.issue_summary || "";
item.detailed_description = item.detailed_description || "";

item.category = item.category || "General Support";
item.priority = item.priority || "Medium";
item.priority_reason = item.priority_reason || "";
item.sentiment = item.sentiment || "Neutral";
item.product_service = item.product_service || "";
item.assigned_team = item.assigned_team || "Customer Success";
item.status = item.status || "Open";

item.confidence_score = Number(item.confidence_score ?? 95);

item.internal_notes =
  item.internal_notes ||
  "Ticket automatically classified by AI.";

// ----------------------------
// Tags
// ----------------------------
if (!Array.isArray(item.tags)) {
  item.tags = [];
}

item.tags = [...new Set(item.tags)];

// ----------------------------
// Google Sheet column names
// ----------------------------
return [
  {
    json: {
      "Ticket ID": `TKT-${Date.now()}`,
      "Customer Name": item.customer_name,
      "Company": item.company,
      "Sender Email": item.sender_email,
      "Email Subject": item.subject,
      "Email Body": item.email_body,
      "Issue Summary": item.issue_summary,
      "Detailed Description": item.detailed_description,
      "Category": item.category,
      "Priority": item.priority,
      "Priority Reason": item.priority_reason,
      "Sentiment": item.sentiment,
      "Product/Service": item.product_service,
      "Assigned Team": item.assigned_team,
      "Tags": item.tags.join(", "),
      "Confidence Score": item.confidence_score,
      "Status": item.status,
      "Internal Notes": item.internal_notes,
      "Received At": new Date().toISOString(),
      "Last Updated": new Date().toISOString()
    }
  }
];

